export const getRosterForBulkEdit = createAsyncThunk(
  "roster/getRosterForBulkEdit",
  async (rosterId, thunkAPI) => {
    const state = thunkAPI.getState().roster;
    if (
      state.bulkEditRoster &&
      isCacheValid("bulkEditRoster", rosterId)
    ) {
      return state.bulkEditRoster;
    }
    const token = getToken();
    const res = await axios.get(`${API_URL}/bulk-edit/${rosterId}`, {
      params: { includePastWeeks: true },
      headers: { Authorization: `Bearer ${token}` },
    });

    cache.bulkEditRoster.data = res.data;
    cache.bulkEditRoster.timestamp = Date.now();
    cache.bulkEditRoster.rosterId = rosterId;

    return res.data;
  }
);

export const searchBulkEditEmployees = createAsyncThunk(
  "roster/searchBulkEditEmployees",
  async ({ rosterId, q, searchBy, department }, thunkAPI) => {
    try {
      const token = getToken();
      const params = new URLSearchParams();
      if (q !== undefined && q !== null && String(q).trim()) params.set("q", String(q).trim());
      if (searchBy !== undefined && searchBy !== null && String(searchBy).trim()) params.set("searchBy", String(searchBy).trim());
      if (department !== undefined && department !== null && String(department).trim()) params.set("department", String(department).trim());

      const query = params.toString();
      const url = `${API_URL}/bulk-edit/${rosterId}/search${query ? `?${query}` : ""}`;

      const res = await axios.get(url, { headers: { Authorization: `Bearer ${token}` } });
      return res.data;
    } catch (err) {
      const message = err.response?.data?.message || err.message;
      return thunkAPI.rejectWithValue(message);
    }
  }
);
