export const exportSavedRoster = createAsyncThunk(
  "roster/exportSavedRoster",
  async ({ month, year }, thunkAPI) => {
    try {
      const token = getToken();

      const response = await fetch(
        `${API_URL}/export-saved?month=${month}&year=${year}`,
        {
          headers: { 
            Authorization: `Bearer ${token}`,
          },
        }
      );

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `HTTP error! status: ${response.status}`);
      }

      const blob = await response.blob();
      
      let filename = `roster_${month}_${year}_saved.xlsx`;
      const contentDisposition = response.headers.get('Content-Disposition');
      if (contentDisposition) {
        const match = contentDisposition.match(/filename="?(.+)"?/);
        if (match && match[1]) {
          filename = match[1];
        }
      }

      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);

      return { 
        success: true, 
        message: "Saved roster Excel file downloaded successfully" 
      };
      
    } catch (err) {
      return thunkAPI.rejectWithValue(err.message || "Failed to export saved roster Excel file");
    }
  }
);
export const exportAttendanceSnapshot = createAsyncThunk(
  "roster/exportAttendanceSnapshot",
  async ({ startDate, endDate, department = "", teamLeader = "", delegatedFrom = "" }, thunkAPI) => {
    try {
      const token = getToken();

      const queryParams = new URLSearchParams({ startDate, endDate });
      const departmentValues = Array.isArray(department) ? department : department ? [department] : [];
      const teamLeaderValues = Array.isArray(teamLeader) ? teamLeader : teamLeader ? [teamLeader] : [];
      departmentValues
        .map((value) => String(value || "").trim())
        .filter(Boolean)
        .forEach((value) => queryParams.append("department", value));
      teamLeaderValues
        .map((value) => String(value || "").trim())
        .filter(Boolean)
        .forEach((value) => queryParams.append("teamLeader", value));
      if (delegatedFrom) queryParams.set("delegatedFrom", delegatedFrom);
      const query = queryParams.toString();

      const response = await fetch(`${API_URL}/export-attendance-snapshot?${query}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `HTTP error! status: ${response.status}`);
      }

      const blob = await response.blob();

      let filename = `attendance_snapshot_${startDate}_to_${endDate}.xlsx`;
      const contentDisposition = response.headers.get("Content-Disposition");
      if (contentDisposition) {
        const match = contentDisposition.match(/filename=\"?(.+?)\"?($|;)/);
        if (match && match[1]) {
          filename = match[1];
        }
      }

      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);

      toast.success("Attendance snapshot downloaded successfully");
      return { success: true };
    } catch (err) {
      return thunkAPI.rejectWithValue(err.message || "Failed to export attendance snapshot");
    }
  }
);
